+
+export const unboundedPreceding = { type: 'unbounded preceding' } as const;
+export const currentRow = { type: 'current row' } as const;
+export const unboundedFollowing = { type: 'unbounded following' } as const;
+
+function position(boundary: WindowBoundary): number {
+	if (boundary === unboundedPreceding) return Number.NEGATIVE_INFINITY;
+	if (boundary === currentRow) return 0;
+	if (boundary === unboundedFollowing) return Number.POSITIVE_INFINITY;
+	return boundary.type === 'preceding' ? -boundary.value : boundary.value;
+}
+
+function assertOffset(name: 'preceding' | 'following', value: number): void {
+	if (!Number.isInteger(value) || value < 0) {
+		throw new Error(`${name}() requires a non-negative integer, received ${value}`);
+	}
+}
+
+export function preceding(value: number): WindowBoundary {
+	assertOffset('preceding', value);
+	return { type: 'preceding', value };
+}
+
+export function following(value: number): WindowBoundary {
+	assertOffset('following', value);
+	return { type: 'following', value };
+}
+
+function frame(type: WindowFrame['type'], spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	if (position(spec.from) > position(spec.to)) {
+		throw new Error('Window frame from boundary must not be ordered after to boundary');
+	}
+	return { type, ...spec };
+}
+
+export function rows(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('rows', spec);
+}
+
+export function range(spec: { from: WindowBoundary; to: WindowBoundary }): WindowFrame {
+	return frame('range', spec);
+}
+
+function boundarySql(boundary: WindowBoundary): SQL {
+	if (boundary === unboundedPreceding) return sql.raw('unbounded preceding');
+	if (boundary === currentRow) return sql.raw('current row');
+	if (boundary === unboundedFollowing) return sql.raw('unbounded following');
+	return sql.raw(`${boundary.value} ${boundary.type}`);
+}
+
+function overSql(spec: WindowSpec | string): SQL {
+	if (typeof spec === 'string') return sql` over ${sql.identifier(spec)}`;
+	const partitionBy = spec.partitionBy === undefined ? [] : Array.isArray(spec.partitionBy) ? spec.partitionBy : [spec.partitionBy];
