+const sales = pgTable('sales', { amount: integer('amount'), group: integer('group') });
+
+test('window helpers compile SQL literals and inline specifications', () => {
+	const db = drizzle.mock();
+	const query = db.select({
+		row: rowNumber().over({ partitionBy: sales.group, orderBy: sales.amount }),
+		rank: denseRank().over({}),
+		tiles: ntile(4).over({ orderBy: sales.amount }),
+		previous: lag(sales.amount, 0).over({ orderBy: sales.amount }),
+		total: windowSum(sales.amount).over({
+			orderBy: sales.amount,
